from dataclasses import dataclass
from enum import Enum
from typing import Optional

class ModelTier(str, Enum):
    TIER_1 = "tier_1"   # Preferred — ≤20B or equivalent
    TIER_2 = "tier_2"   # Justified — 20B–100B
    TIER_3 = "tier_3"   # Frontier — >100B / expensive API

@dataclass
class ModelEfficiencyProfile:
    model_id: str                     # e.g. "meta-llama/Meta-Llama-3-70B-Instruct"
    provider: str                     # "huggingface" | "openai" | "anthropic" | "self-hosted"
    approximate_params_b: Optional[float]   # None for closed models
    co2e_per_1m_tokens_kg: float      # Measured; None if not yet benchmarked
    region_used_for_measurement: str   # e.g. "eu-west-1"
    pue_assumed: float = 1.2
    measurement_methodology: str = "codecarbon"
    measured_by: Optional[str] = None
    tier: Optional[ModelTier] = None  # Set by governance team at approval

    def tier_label(self) -> str:
        if self.tier:
            return self.tier.value
        # Auto-classify by params if tier not explicitly assigned
        if self.approximate_params_b and self.approximate_params_b <= 20:
            return ModelTier.TIER_1.value
        if self.approximate_params_b and self.approximate_params_b <= 100:
            return ModelTier.TIER_2.value
        return ModelTier.TIER_3.value

    def budget_multiplier(self) -> int:
        t = self.tier_label()
        return {ModelTier.TIER_1.value: 1, ModelTier.TIER_2.value: 8, ModelTier.TIER_3.value: 100}[t]

    def summary(self) -> str:
        return (
            f"{self.model_id} [{self.tier_label()}]: "
            f"{self.co2e_per_1m_tokens_kg:.2f} kg CO₂e/1M tokens "
            f"(budget multiplier: {self.budget_multiplier()}×)"
        )

from dataclasses import dataclass, field
from threading import Lock

# Monthly carbon budget per business unit (kg CO₂e)
BU_MONTHLY_BUDGET_KG: dict[str, float] = {
    "product-ai":    500.0,
    "data-science":  300.0,
    "platform":      200.0,
    "marketing-ai":  100.0,
}

# Budget consumption is measured in 'carbon units': 1 unit = 1 Tier-1 token / 1M
# Tier 2 costs 8 units/1M tokens; Tier 3 costs 100 units/1M tokens

@dataclass
class BUCarbonBudget:
    bu: str
    monthly_budget_kg: float
    _consumed_kg: float = field(default=0.0, repr=False)
    _lock: Lock = field(default_factory=Lock, repr=False)

    def consume(self, co2e_kg: float) -> bool:
        """Return True if consumption was allowed; False if budget exceeded."""
        with self._lock:
            if self._consumed_kg + co2e_kg > self.monthly_budget_kg:
                return False
            self._consumed_kg += co2e_kg
            return True

    def remaining_kg(self) -> float:
        return max(0.0, self.monthly_budget_kg - self._consumed_kg)

    def utilisation(self) -> float:
        return self._consumed_kg / self.monthly_budget_kg

    def is_exhausted(self) -> bool:
        return self._consumed_kg >= self.monthly_budget_kg

# At the API proxy layer:
def route_request(bu: str, model_profile: "ModelEfficiencyProfile",
                  tokens_requested: int, budget_registry: dict[str, BUCarbonBudget]) -> bool:
    estimated_co2e = (tokens_requested / 1_000_000) * model_profile.co2e_per_1m_tokens_kg
    budget = budget_registry.get(bu)
    if not budget:
        return True  # Unknown BU — allow but log for review
    if not budget.consume(estimated_co2e):
        raise RuntimeError(
            f"Carbon budget exhausted for {bu}: "
            f"{budget.remaining_kg():.2f} kg remaining, "
            f"request requires {estimated_co2e:.4f} kg. "
            f"Use a Tier 1 model or request a budget increase."
        )
    return True
